import{_ as t,o,c as a,au as r}from"./chunks/framework.Bpqx6pAq.js";const h=JSON.parse('{"title":"Catalog utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.catalog.md","filePath":"api/map/utilities/utils.catalog.md"}'),i={name:"api/map/utilities/utils.catalog.md"};function s(l,e,n,d,c,g){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="catalog-utilities" tabindex="-1">Catalog utilities <a class="header-anchor" href="#catalog-utilities" aria-label="Permalink to &quot;Catalog utilities&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This module provides low-level functions for interacting with the KDK catalog service: fetching layers, categories, sublegends, and views; organizing them by category; and managing JWT authentication tokens in layer URLs.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="seturljwt-item-path-baseurl-jwtfield-jwt" tabindex="-1"><code>setUrlJwt(item, path, baseUrl, jwtField, jwt)</code> <a class="header-anchor" href="#seturljwt-item-path-baseurl-jwtfield-jwt" aria-label="Permalink to &quot;`setUrlJwt(item, path, baseUrl, jwtField, jwt)`&quot;">​</a></h3><p>Injects a JWT token as a query parameter into a URL stored at <code>path</code> in an <code>item</code> object. Handles token refresh by stripping any existing JWT before adding the new one.</p><ul><li><strong>Parameters:</strong><ul><li><code>item</code> <em>(Object)</em>: The object containing the URL property.</li><li><code>path</code> <em>(string)</em>: Lodash path to the URL property within <code>item</code>.</li><li><code>baseUrl</code> <em>(string)</em>: Only URLs starting with this base are modified.</li><li><code>jwtField</code> <em>(string)</em>: The query parameter name for the JWT.</li><li><code>jwt</code> <em>(string)</em>: The JWT token value.</li></ul></li></ul><hr><h3 id="setenginejwt-layers-planetapi" tabindex="-1"><code>setEngineJwt(layers, planetApi?)</code> <a class="header-anchor" href="#setenginejwt-layers-planetapi" aria-label="Permalink to &quot;`setEngineJwt(layers, planetApi?)`&quot;">​</a></h3><p>Injects gateway and/or API JWT tokens into all relevant URL properties of a list of layers. Handles both Leaflet and Cesium URL properties, as well as OGC protocol URLs.</p><ul><li><strong>Parameters:</strong><ul><li><code>layers</code> <em>(Array)</em>: The layers to update.</li><li><code>planetApi</code> <em>(Object, optional)</em>: The API client instance. Defaults to the application API.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Array&gt;</code> — The updated layers array.</li></ul><hr><h3 id="getlayersbycategory-layers-categories" tabindex="-1"><code>getLayersByCategory(layers, categories)</code> <a class="header-anchor" href="#getlayersbycategory-layers-categories" aria-label="Permalink to &quot;`getLayersByCategory(layers, categories)`&quot;">​</a></h3><p>Organises a list of layers into groups based on category definitions. Built-in categories filter by query; user-defined categories filter by explicit layer name list. Layers are removed from the input array once assigned to a category.</p><ul><li><strong>Parameters:</strong><ul><li><code>layers</code> <em>(Array | Object)</em>: The layers to organise.</li><li><code>categories</code> <em>(Array)</em>: Category definitions, each with optional <code>options.filter</code>, <code>options.orderBy</code>, <code>options.order</code>, or <code>layers</code> array.</li></ul></li><li><strong>Returns:</strong> <code>Object</code> — A map of category name to sorted layer array.</li></ul><hr><h3 id="getorphanlayers-layers-layersbycategory" tabindex="-1"><code>getOrphanLayers(layers, layersByCategory)</code> <a class="header-anchor" href="#getorphanlayers-layers-layersbycategory" aria-label="Permalink to &quot;`getOrphanLayers(layers, layersByCategory)`&quot;">​</a></h3><p>Returns layers that were not assigned to any category, sorted by <code>_id</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>layers</code> <em>(Array | Object)</em>: The full layer list.</li><li><code>layersByCategory</code> <em>(Object)</em>: The output of <code>getLayersByCategory</code>.</li></ul></li><li><strong>Returns:</strong> <code>Array</code></li></ul><hr><h3 id="processtranslations-item" tabindex="-1"><code>processTranslations(item)</code> <a class="header-anchor" href="#processtranslations-item" aria-label="Permalink to &quot;`processTranslations(item)`&quot;">​</a></h3><p>Registers i18n translations from <code>item.i18n</code> and sets <code>item.label</code> and <code>item.description</code> using <code>i18n.tie</code> if not already set.</p><ul><li><strong>Parameters:</strong><ul><li><code>item</code> <em>(Object)</em>: A catalog item (layer, category, view, etc.) that may have an <code>i18n</code> property.</li></ul></li></ul><hr><h3 id="getlayers-options" tabindex="-1"><code>getLayers(options?)</code> <a class="header-anchor" href="#getlayers-options" aria-label="Permalink to &quot;`getLayers(options?)`&quot;">​</a></h3><p>Fetches layers from the catalog service.</p><ul><li><strong>Parameters:</strong><ul><li><code>options.query</code> <em>(Object, optional)</em>: Additional query filter.</li><li><code>options.context</code> <em>(string, optional)</em>: Service context ID.</li><li><code>options.project</code> <em>(Object, optional)</em>: Project to scope the query to.</li><li><code>options.planetApi</code> <em>(Object, optional)</em>: API client to use.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Array&gt;</code> — The fetched layers with translations processed and JWT tokens injected.</li></ul><hr><h3 id="getcategories-options" tabindex="-1"><code>getCategories(options?)</code> <a class="header-anchor" href="#getcategories-options" aria-label="Permalink to &quot;`getCategories(options?)`&quot;">​</a></h3><p>Fetches categories from the catalog service (query filters for <code>type: &#39;Category&#39;</code>).</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Array&gt;</code></li></ul><hr><h3 id="getsublegends-options" tabindex="-1"><code>getSublegends(options?)</code> <a class="header-anchor" href="#getsublegends-options" aria-label="Permalink to &quot;`getSublegends(options?)`&quot;">​</a></h3><p>Fetches sublegends from the catalog service (query filters for <code>type: &#39;Sublegend&#39;</code>).</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Array&gt;</code></li></ul><hr><h3 id="getlayersbysublegend-layers-sublegends" tabindex="-1"><code>getLayersBySublegend(layers, sublegends)</code> <a class="header-anchor" href="#getlayersbysublegend-layers-sublegends" aria-label="Permalink to &quot;`getLayersBySublegend(layers, sublegends)`&quot;">​</a></h3><p>Organises layers by sublegend, similar to <code>getLayersByCategory</code> but based on <code>options.filter</code> only.</p><ul><li><strong>Returns:</strong> <code>Object</code> — A map of sublegend name to layer array.</li></ul><hr><h3 id="getviews-options" tabindex="-1"><code>getViews(options?)</code> <a class="header-anchor" href="#getviews-options" aria-label="Permalink to &quot;`getViews(options?)`&quot;">​</a></h3><p>Fetches views (contexts) from the catalog service (query filters for <code>type: &#39;Context&#39;</code>).</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Array&gt;</code></li></ul><hr><h3 id="ordercatalogitemsby-items-itemsorder" tabindex="-1"><code>orderCatalogItemsBy(items, itemsOrder)</code> <a class="header-anchor" href="#ordercatalogitemsby-items-itemsorder" aria-label="Permalink to &quot;`orderCatalogItemsBy(items, itemsOrder)`&quot;">​</a></h3><p>Reorders an array of catalog items so that items whose <code>_id</code> or <code>name</code> appear in <code>itemsOrder</code> are moved to the front, in the order specified.</p><ul><li><strong>Parameters:</strong><ul><li><code>items</code> <em>(Array)</em>: The items array to reorder in place.</li><li><code>itemsOrder</code> <em>(Array)</em>: An array of <code>_id</code> or <code>name</code> strings defining the desired order.</li></ul></li></ul>',47)])])}const u=t(i,[["render",s]]);export{h as __pageData,u as default};
